    $this->_admSessionName = Config::get('session.admin_name');

    if ($user === null) {
        if (Session::exists($this->_sessionName)) {
            $user = Session::get($this->_sessionName);
            if ($this->find($user, $field)) {
                $this->_isLoggedIn = true;
            }
