        if (Session::exists($this->_admSessionName)) {
            $user = Session::get($this->_admSessionName);
            if ($user == $this->data()->id && $this->find($user, $field)) {
                $this->_isAdmLoggedIn = true;
            }
        }
    } else {
        $this->find($user, $field);
    }
}

